using System;using System.Collections.Generic;using System.Linq;class A{static int W,H;static bool[,]grid,vis;static double[]SL=new double[5];static double LS;static void Main(){var p=Console.ReadLine().Split(' ');W=int.Parse(p[0]);H=int.Parse(p[1]);grid=new bool[H,W];vis=new bool[H,W];var dwe=Console.ReadLine().Split(' ');int pi=0;for(int i=0;i<dwe.Length;i+=2){bool c=dwe[i]=="B";int l=int.Parse(dwe[i+1]);for(int j=0;j<l;j++){int y=pi/W,x=pi%W;if(y<H)grid[y,x]=c;pi++;}}int[]bc=new int[H];for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(grid[y,x])bc[y]++;var groups=new List<List<int>>();var g=new List<int>();for(int y=0;y<H;y++){if(bc[y]>W*0.8){if(g.Count==0||y==g[^1]+1)g.Add(y);else{groups.Add(g);g=new List<int>{y};}}else if(g.Count>0){groups.Add(g);g=new();}}if(g.Count>0)groups.Add(g);int bi=0;double bd=1e9;for(int i=0;i+4<groups.Count;i++){var cs=new double[5];for(int j=0;j<5;j++)cs[j]=groups[i+j].Average();double avg=0;var sp=new double[4];for(int j=0;j<4;j++){sp[j]=cs[j+1]-cs[j];avg+=sp[j];}avg/=4;double d=sp.Sum(s=>Math.Abs(s-avg));if(d<bd){bd=d;bi=i;}}for(int j=0;j<5;j++)SL[j]=groups[bi+j].Average();LS=(SL[4]-SL[0])/4;var notes=new List<(int x,string n)>();string nm="AGFEDCBAGFEDC";for(int x=0;x<W;x++)for(int y=0;y<H;y++){if(grid[y,x]&&!vis[y,x]){var q=new Queue<(int,int)>();q.Enqueue((y,x));var px=new List<(int y,int x)>();int mx=W,MX=-1,my=H,MY=-1;while(q.Count>0){var(cy,cx)=q.Dequeue();if(cy<0||cy>=H||cx<0||cx>=W||vis[cy,cx]||!grid[cy,cx])continue;vis[cy,cx]=true;px.Add((cy,cx));mx=Math.Min(mx,cx);MX=Math.Max(MX,cx);my=Math.Min(my,cy);MY=Math.Max(MY,cy);for(int dy=-1;dy<=1;dy++)for(int dx=-1;dx<=1;dx++)if(dy!=0||dx!=0)q.Enqueue((cy+dy,cx+dx));}if(px.Count<15)continue;var yw=new Dictionary<int,(int mn,int mx)>();foreach(var(py,px2)in px){if(!yw.ContainsKey(py))yw[py]=(px2,px2);else{var v=yw[py];yw[py]=(Math.Min(v.mn,px2),Math.Max(v.mx,px2));}}int yc=-1,mw=-1;foreach(var(yy,v)in yw){int w=v.mx-v.mn+1;if(w>mw){mw=w;yc=yy;}}double ed=LS*0.6,eM=LS*1.5;if(mw<ed||mw>eM)continue;if(MY-my+1<ed||MX-mx+1>W*0.5)continue;int hr=(int)(LS/2),hmy=Math.Max(0,yc-hr),hMy=Math.Min(H-1,yc+hr);int bp=px.Count(pp=>pp.y>=hmy&&pp.y<=hMy&&pp.x>=mx&&pp.x<=MX);int tp=(MX-mx+1)*(hMy-hmy+1);double fr=tp>0?(double)bp/tp:1;char nt=fr>0.5?'Q':'H';double hs=LS/2;int cl=0;double md=1e9;for(int i=0;i<13;i++){double ny=SL[4]-hs*2+hs*i;double d=Math.Abs(yc-ny);if(d<md){md=d;cl=i;}}notes.Add((mx,$"{nm[cl]}{nt}"));}}notes.Sort((a,b)=>a.x-b.x);Console.Write(string.Join(" ",notes.Select(n=>n.n)));}}